/**
 * Analytics Middleware
 * ====================
 * Redux middleware for tracking user actions to analytics.
 * 
 * Features:
 * - Tracks user interactions
 * - Can integrate with Google Analytics, Mixpanel, etc.
 */

import { type Middleware } from "@reduxjs/toolkit";

/**
 * Analytics middleware
 * 
 * In production, this would send events to analytics service
 */
export const analytics: Middleware = (_store) => (next) => (action) => {
  if (typeof action === "object" && action !== null && "type" in action) {
    const actionType = (action as { type: string }).type;
    // Track certain actions
    const trackableActions = [
      "auth/loginSuccess",
      "auth/logout",
    ];

    const shouldTrack = trackableActions.includes(actionType);

    if (shouldTrack) {
      // In production, send to analytics:
      // window.gtag?.("event", actionType, { /* properties */ });
      // or
      // mixpanel.track(actionType, { /* properties */ });

      console.warn("[ANALYTICS]", {
        event: actionType,
        timestamp: new Date().toISOString(),
      });
    }
  }

  return next(action);
};
