import {
  FileText,
  FolderTree,
  ListOrdered,
  Package,
  ShoppingCart,
  Users,
  type LucideIcon,
} from "lucide-react";

const iconRegistry = new Map<string, LucideIcon>([
  ["ShoppingCart", ShoppingCart],
  ["Package", Package],
  ["Users", Users],
  ["FileText", FileText],
  ["FolderTree", FolderTree],
  ["ListOrdered", ListOrdered],
]);

export function registerSidebarIcon(name: string, icon: LucideIcon) {
  iconRegistry.set(name, icon);
}

export function getSidebarIcon(iconName?: string): LucideIcon {
  if (!iconName) {
    return FileText;
  }

  return iconRegistry.get(iconName) ?? FileText;
}