import { QueryClient } from "@tanstack/react-query";

/**
 * Query Client Configuration
 * ===========================
 * Enterprise-grade defaults for React Query.
 * 
 * Key decisions:
 * - staleTime: 5min (metadata doesn't change frequently)
 * - refetchOnWindowFocus: false (avoid unexpected UI updates mid-use)
 * - refetchOnReconnect: true (ensure fresh data after offline period)
 * - retry: 1 (fail fast, avoid user wait time)
 */
export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 5 * 60 * 1000, // 5 minutes
      gcTime: 10 * 60 * 1000, // 10 minutes (garbage collection)
      retry: 1,
      refetchOnWindowFocus: false,
      refetchOnReconnect: true,
      refetchOnMount: true,
    },
    mutations: {
      retry: 0, // Never retry mutations (avoid duplicate creates/updates)
    },
  },
});
